+    QObject::connect(ui_.max_color,
+        SIGNAL(colorEdited(const QColor &)),
+        this,
+        SLOT(UpdateColors()));
+    QObject::connect(ui_.min_color,
+        SIGNAL(colorEdited(const QColor &)),
