+        SLOT(UpdateColors()));
+    QObject::connect(ui_.minValue,
+        SIGNAL(valueChanged(double)),
+        this,
+        SLOT(MinValueChanged(double)));
+    QObject::connect(ui_.maxValue,
+        SIGNAL(valueChanged(double)),
+        this,
