+  void PointCloud2Plugin::TopicEdited()
+  {
+    if (ui_.topic->text().toStdString() != topic_)
+    {
+      initialized_ = false;
+      scans_.clear();
+      has_message_ = false;
+      topic_ = boost::trim_copy(ui_.topic->text().toStdString());
+      PrintWarning("No messages received.");
