+      ui_.min_color->setVisible(true);
+      ui_.maxColorLabel->setVisible(true);
+      ui_.minColorLabel->setVisible(true);
+      ui_.minValueLabel->setVisible(true);
+      ui_.maxValueLabel->setVisible(true);
