+    ROS_ERROR("Error: %s", message.c_str());
+    QPalette p(ui_.status->palette());
+    p.setColor(QPalette::Text, Qt::red);
+    ui_.status->setPalette(p);
+    ui_.status->setText(message.c_str());
+  }
