+MapCanvas::MapCanvas(QWidget* parent) :
+  QGLWidget(parent),
+  has_pixel_buffers_(false),
+  pixel_buffer_size_(0),
+  pixel_buffer_index_(0),
+  capture_frames_(false),
+  initialized_(false),
+  fix_orientation_(false),
