+  void MultiresImagePlugin::GetCenterPoint(double x, double y)
+  {
+      tf::Point point(x, y, 0);
+      tf::Point center = inverse_transform_ * point;
+      center_x_ = center.getX();
+      center_y_ = center.getY();
+  }
