+  void RobotImagePlugin::SelectFile()
+  {
+    QFileDialog dialog(config_widget_, "Select PNG Image");
+    dialog.setFileMode(QFileDialog::ExistingFile);
+    dialog.setNameFilter(tr("PNG Image Files (*.png)"));
+
+    dialog.exec();
