+    top_right_ = tf::Point(width_ / 2.0, height_ / 2.0, 0);
+    bottom_left_ = tf::Point(-width_ / 2.0, -height_/2.0, 0);
+    bottom_right_ = tf::Point(width_ / 2.0, -height_ / 2.0, 0);
