+  void TexturedMarkerPlugin::MarkerArrayCallback(const marti_visualization_msgs::TexturedMarkerArrayConstPtr markers)
+  {
+    for (unsigned int i = 0; i < markers->markers.size(); i++)
+    {
+      ProcessMarker(markers->markers[i]);
+    }
+  }
