+  void TfFramePlugin::BufferSizeChanged(int value)
+  {
+    buffer_size_ = value;
+
+    if (buffer_size_ > 0)
+    {
+      while (static_cast<int>(points_.size()) > buffer_size_)
+      {
+        points_.pop_front();
+      }
+    }
+
+    canvas_->update();
